    const w = window.innerWidth, h = window.innerHeight;
    canvas.width = Math.floor(w * dpr);
    canvas.height = Math.floor(h * dpr);
    const ctx = canvas.getContext("2d");
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0); // draw in CSS pixels
    return { ctx, width: w, height: h, dpr };
  }
- Initialize: const { ctx, width, height } = fitCanvas(canvas);
  const sim = new Simulation(width, height, 300, 240); // 300 boids, fast
  const renderer = new Renderer(ctx); renderer.setSize(width, height);
- Handle resize: on window resize, call fitCanvas again, update renderer.setSize and sim.resize.
- Animation loop:
    let last = performance.now();
    function frame(t){
      const dt = Math.min((t - last) / 1000, 0.05);
      last = t;
      sim.update(dt);
      renderer.clear();
      renderer.draw(sim.boidsArray);
      requestAnimationFrame(frame);
    }
    requestAnimationFrame(frame);
- No UI or config.
write_file then done('ok').""",
    contract,
    model="fast",
)

results = yield wait(h1, h2, h3, h4, h5, h6)

# Verify files exist
required = [
    "output/boids-simulation/index.html",
    "output/boids-simulation/styles.css",
    "output/boids-simulation/js/boid.js",
    "output/boids-simulation/js/simulation.js",
    "output/boids-simulation/js/renderer.js",
    "output/boids-simulation/js/main.js",
]
missing = [p for p in required if p not in ls("output/boids-simulation") and not os.path.exists(p)]
if missing:
    done(f"ERROR: Missing files: {missing}")

# Read back and sanity-check wiring
idx = read_file("output/boids-simulation/index.html")
mainjs = read_file("output/boids-simulation/js/main.js")
simjs = read_file("output/boids-simulation/js/simulation.js")
boidjs = read_file("output/boids-simulation/js/boid.js")
rendjs = read_file("output/boids-simulation/js/renderer.js")

issues = []

if 'id="boids-canvas"' not in idx:
    issues.append("index.html missing canvas with id 'boids-canvas'")
if 'type="module"' not in idx or 'src="./js/main.js"' not in idx:
    issues.append("index.html missing module script to ./js/main.js")
if "export class Boid" not in boidjs or "spawnBoids" not in boidjs:
    issues.append("boid.js missing Boid class or spawnBoids export")
if "export class Simulation" not in simjs or 'from "./boid.js"' not in simjs:
    issues.append("simulation.js missing Simulation class or import from boid.js")
if "export class Renderer" not in rendjs:
    issues.append("renderer.js missing Renderer class export")
if 'from "./simulation.js"' not in mainjs or 'from "./renderer.js"' not in mainjs:
    issues.append("main.js missing imports from simulation.js/renderer.js")
if "requestAnimationFrame" not in mainjs:
    issues.append("main.js missing animation loop")

if issues:
    done("Sanity check failed: " + "; ".join(issues))

# Final message
done("Boids simulation written to output/boids-simulation with modular JS (boid, simulation, renderer) and index.html entrypoint. Verified imports and animation loop wiring.")

